4.1 Pre-Computed Summaries


Show code
# Traffic medium
traffic_summary &lt;- ds |&gt;
  filter(event_name == "page_view") |&gt;
  mutate(
    medium_clean = case_when(
      is.na(traffic_medium)      ~ "(not set)",
      traffic_medium == "(none)" ~ "direct",
      TRUE                       ~ traffic_medium
    )
  ) |&gt;
  count(medium_clean, name = "page_views") |&gt;
  arrange(desc(page_views))

# Device
device_summary &lt;- ds |&gt;
  filter(!is.na(device_category)) |&gt;
  group_by(device_category) |&gt;
  summarise(
    n_events       = n(),
    n_unique_users = n_distinct(user_pseudo_id)
  ) |&gt;
  arrange(desc(n_events)) |&gt;
  mutate(pct_events = n_events / sum(n_events) * 100)

# Events by date
events_by_date &lt;- ds |&gt;
  count(event_date, name = "n_events") |&gt;
  arrange(event_date)

# Top event types
event_types &lt;- ds |&gt;
  count(event_name, name = "count") |&gt;
  arrange(desc(count)) |&gt;
  slice_head(n = 8)

# Geo
geo_summary &lt;- ds |&gt;
  filter(!is.na(geo_country), event_name == "page_view") |&gt;
  count(geo_country, name = "page_views") |&gt;
  arrange(desc(page_views)) |&gt;
  slice_head(n = 10)

# KPIs
total_events    &lt;- nrow(ds)
total_users     &lt;- n_distinct(ds$user_pseudo_id)
total_pv        &lt;- ds |&gt; filter(event_name == "page_view") |&gt; nrow()
events_per_user &lt;- total_events / total_users
pv_per_user     &lt;- total_pv / total_users
top_medium      &lt;- traffic_summary$medium_clean[1]
top_device      &lt;- device_summary$device_category[1]

