5.2 Markov Chain Attribution Model
A Markov chain attribution model treats the user journey as a sequence of channel states. It estimates each channel’s contribution by computing the removal effect: how much would conversion probability drop if that channel were removed entirely from all journeys? Channels that appear early and often in high-converting paths receive proportionally more credit.

5.2.1 Attribution Results


Show code
library(tidyr)

# ── Load attribution dataset ───────────────────────────────────────────────────
attr_raw &lt;- readr::read_csv(
  here::here("data", "attribution_dataset.csv"),
  show_col_types = FALSE
)

channel_cols &lt;- grep("^channel", names(attr_raw), value = TRUE)
channels_list &lt;- c("Direct", "Email", "Organic", "Paid Search", "Paid Social", "Referral")

# ── Last-Touch Attribution ─────────────────────────────────────────────────────
converters &lt;- attr_raw |&gt; filter(user_purchase == 1)

last_touch_attr &lt;- converters |&gt;
  rowwise() |&gt;
  mutate(
    last_ch = {
      vals &lt;- c_across(all_of(channel_cols))
      vals &lt;- vals[!is.na(vals)]
      if (length(vals) &gt; 0) tail(vals, 1) else NA_character_
    }
  ) |&gt;
  ungroup() |&gt;
  filter(!is.na(last_ch)) |&gt;
  count(last_ch, name = "credit") |&gt;
  mutate(pct = round(credit / sum(credit) * 100, 2)) |&gt;
  rename(Channel = last_ch, Last_Touch = pct) |&gt;
  select(Channel, Last_Touch)

# ── First-Touch Attribution ────────────────────────────────────────────────────
first_touch_attr &lt;- converters |&gt;
  rowwise() |&gt;
  mutate(
    first_ch = {
      vals &lt;- c_across(all_of(channel_cols))
      vals &lt;- vals[!is.na(vals)]
      if (length(vals) &gt; 0) vals[1] else NA_character_
    }
  ) |&gt;
  ungroup() |&gt;
  filter(!is.na(first_ch)) |&gt;
  count(first_ch, name = "credit") |&gt;
  mutate(pct = round(credit / sum(credit) * 100, 2)) |&gt;
  rename(Channel = first_ch, First_Touch = pct) |&gt;
  select(Channel, First_Touch)

# ── Linear Attribution ─────────────────────────────────────────────────────────
linear_credits &lt;- converters |&gt;
  rowwise() |&gt;
  mutate(
    path = list({
      vals &lt;- c_across(all_of(channel_cols))
      vals[!is.na(vals)]
    }),
    n_ch = length(path)
  ) |&gt;
  ungroup() |&gt;
  filter(n_ch &gt; 0) |&gt;
  unnest(path) |&gt;
  group_by(users_id, path, n_ch) |&gt;
  summarise(.groups = "drop") |&gt;
  mutate(credit = 1 / n_ch) |&gt;
  group_by(path) |&gt;
  summarise(total_credit = sum(credit), .groups = "drop") |&gt;
  mutate(pct = round(total_credit / sum(total_credit) * 100, 2)) |&gt;
  rename(Channel = path, Linear = pct) |&gt;
  select(Channel, Linear)

# ── Markov Chain Attribution (Absorbing Chain / Removal Effect) ────────────────
# Build transition counts
build_transitions &lt;- function(df, channel_cols) {
  trans &lt;- list()
  for (i in seq_len(nrow(df))) {
    path &lt;- unlist(df[i, channel_cols])
    path &lt;- path[!is.na(path)]
    if (length(path) == 0) next
    outcome &lt;- if (df$user_purchase[i] == 1) "conversion" else "null"

    # start -&gt; first
    from &lt;- "start"; to &lt;- path[1]
    trans[[from]][[to]] &lt;- (trans[[from]][[to]] %||% 0) + 1

    # channel -&gt; channel
    if (length(path) &gt; 1) {
      for (j in seq_len(length(path) - 1)) {
        from &lt;- path[j]; to &lt;- path[j+1]
        trans[[from]][[to]] &lt;- (trans[[from]][[to]] %||% 0) + 1
      }
    }
    # last -&gt; outcome
    from &lt;- tail(path, 1)
    trans[[from]][[outcome]] &lt;- (trans[[from]][[outcome]] %||% 0) + 1
  }
  trans
}

`%||%` &lt;- function(a, b) if (!is.null(a)) a else b

trans_counts &lt;- build_transitions(attr_raw, channel_cols)

# Convert to probabilities
trans_prob &lt;- lapply(trans_counts, function(x) {
  total &lt;- sum(unlist(x))
  lapply(x, function(v) v / total)
})

# Build Q and R matrices for absorbing chain
all_transient &lt;- c(channels_list, "start")
absorbing     &lt;- c("conversion", "null")
n_t &lt;- length(all_transient)
state_idx &lt;- setNames(seq_along(all_transient), all_transient)

Q &lt;- matrix(0, n_t, n_t, dimnames = list(all_transient, all_transient))
R &lt;- matrix(0, n_t, 2,   dimnames = list(all_transient, absorbing))

for (s in all_transient) {
  probs &lt;- trans_prob[[s]]
  if (is.null(probs)) next
  for (t in names(probs)) {
    p &lt;- probs[[t]]
    if (t %in% all_transient) {
      Q[s, t] &lt;- p
    } else if (t %in% absorbing) {
      R[s, t] &lt;- p
    }
  }
}

# Fundamental matrix and absorption probabilities
N_mat &lt;- solve(diag(n_t) - Q)
B_mat &lt;- N_mat %*% R

baseline_conv &lt;- B_mat["start", "conversion"]

# Removal effect for each channel
removal_effects &lt;- sapply(channels_list, function(ch) {
  Q2 &lt;- Q; R2 &lt;- R
  # Redirect transitions TO ch → null
  for (s in all_transient) {
    if (Q2[s, ch] &gt; 0) {
      R2[s, "null"] &lt;- R2[s, "null"] + Q2[s, ch]
      Q2[s, ch] &lt;- 0
    }
  }
  # ch itself: absorb to null
  Q2[ch, ] &lt;- 0
  R2[ch, ] &lt;- c(0, 1)

  tryCatch({
    N2 &lt;- solve(diag(n_t) - Q2)
    B2 &lt;- N2 %*% R2
    max(0, baseline_conv - B2["start", "conversion"])
  }, error = function(e) 0)
})

markov_pct_vals &lt;- round(removal_effects / sum(removal_effects) * 100, 2)

markov_attr &lt;- data.frame(
  Channel = names(markov_pct_vals),
  Markov  = as.numeric(markov_pct_vals)
)

# ── Combined comparison table ──────────────────────────────────────────────────
comparison &lt;- last_touch_attr |&gt;
  full_join(first_touch_attr, by = "Channel") |&gt;
  full_join(linear_credits,   by = "Channel") |&gt;
  full_join(markov_attr,      by = "Channel") |&gt;
  arrange(desc(Last_Touch))



Note on attribution dataset: The attribution analysis uses a separate dataset (attribution_dataset.csv) containing 1,000 user journeys across 6 channels (Direct, Email, Organic, Paid Search, Paid Social, Referral), with user_purchase as the conversion indicator (10% conversion rate, n=100 converters). Four models are compared: Last-Touch, First-Touch, Linear, and Markov Chain (removal effect via absorbing Markov chain). The dataset contains journeys of 1–8 touchpoints (mean = 4.2).



Show code
comparison_long &lt;- comparison |&gt;
  tidyr::pivot_longer(
    cols = c(Last_Touch, First_Touch, Linear, Markov),
    names_to  = "Model",
    values_to = "Attribution"
  ) |&gt;
  mutate(Model = factor(Model, levels = c("First_Touch", "Linear", "Last_Touch", "Markov")))

ggplot(comparison_long, aes(x = Channel, y = Attribution, fill = Model)) +
  geom_bar(stat = "identity", position = position_dodge(width = 0.85),
           width = 0.8, na.rm = TRUE) +
  geom_text(
    aes(label = ifelse(is.na(Attribution), "", paste0(round(Attribution, 1), "%"))),
    position = position_dodge(width = 0.85),
    vjust = -0.4, size = 2.8, na.rm = TRUE
  ) +
  labs(
    x = "Channel", y = "Attribution (%)", fill = "Model",
    title = "Multi-Touch Attribution: Four Models Compared",
    caption = "Based on attribution_dataset.csv — 1,000 users, 100 converters"
  ) +
  scale_fill_manual(values = c(
    "First_Touch" = "#59A14F",
    "Linear"      = "#F28E2B",
    "Last_Touch"  = "#4E79A7",
    "Markov"      = "#E15759"
  )) +
  scale_y_continuous(expand = expansion(mult = c(0, 0.15))) +
  theme_minimal(base_size = 13) +
  theme(axis.text.x = element_text(angle = 30, hjust = 1))





Four attribution models compared by channel. Each model tells a different story about where conversion credit belongs.






Show code
comparison |&gt;
  filter(!is.na(Markov)) |&gt;
  ggplot(aes(x = Last_Touch, y = Markov, label = Channel)) +
  geom_abline(slope = 1, intercept = 0, linetype = "dashed", color = "gray60") +
  geom_point(size = 4, color = "#E15759") +
  ggrepel::geom_text_repel(size = 4, fontface = "bold") +
  labs(
    x = "Last-Touch Attribution (%)",
    y = "Markov Attribution (%)",
    title = "Last-Touch vs. Markov: Which Channels Are Mis-Attributed?",
    caption = "Channels above the dashed line are undervalued by Last-Touch; below = overvalued"
  ) +
  theme_minimal(base_size = 13)





Last-Touch vs Markov: the two most contrasting models. Channels above the diagonal are undervalued by Last-Touch.






